import React, { useState, useRef, useEffect } from 'react';
import {
  View, StyleSheet, ScrollView, KeyboardAvoidingView, Platform, TouchableOpacity, Animated,
} from 'react-native';
import { TextInput, Text } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';

export default function AddProductScreen({ navigation }) {
  const [formData, setFormData] = useState({ name: '', category: 'Vegetables', price: '', stock: '', unit: 'kg', description: '' });
  const [loading, setLoading] = useState(false);
  const [isOrganic, setIsOrganic] = useState(false);
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const slideAnim = useRef(new Animated.Value(30)).current;

  useEffect(() => {
    Animated.parallel([
      Animated.timing(fadeAnim, { toValue: 1, duration: 500, useNativeDriver: true }),
      Animated.timing(slideAnim, { toValue: 0, duration: 500, useNativeDriver: true }),
    ]).start();
  }, []);

  const updateFormData = (key, value) => setFormData(prev => ({ ...prev, [key]: value }));

  const handleSubmit = async () => {
    if (!formData.name || !formData.price || !formData.stock) { alert('Please fill in all required fields'); return; }
    setLoading(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 1000));
      alert('Product added successfully!');
      navigation.goBack();
    } catch (error) { alert('Failed to add product'); }
    finally { setLoading(false); }
  };

  const categories = [
    { value: 'Vegetables', icon: '🥬', gradient: ['#00C853', '#00E676'] },
    { value: 'Fruits', icon: '🍎', gradient: ['#FF6B6B', '#EE5A24'] },
    { value: 'Grains', icon: '🌾', gradient: ['#F39C12', '#E67E22'] },
    { value: 'Dairy', icon: '🥛', gradient: ['#74B9FF', '#0984E3'] },
  ];

  const InputField = ({ icon, label, value, onChangeText, ...props }) => (
    <View style={s.inputWrapper}>
      <Icon name={icon} size={20} color="#69F0AE" style={s.inputIcon} />
      <TextInput
        label={label}
        value={value}
        onChangeText={onChangeText}
        style={s.input}
        textColor="#fff"
        underlineColor="transparent"
        activeUnderlineColor="#00C853"
        theme={{ colors: { onSurfaceVariant: 'rgba(255,255,255,0.4)', onSurface: '#fff' } }}
        {...props}
      />
    </View>
  );

  return (
    <LinearGradient colors={['#0a1a0f', '#0d2818', '#0a1a0f']} style={s.container}>
      <View style={s.orb1} /><View style={s.orb2} />

      {/* Header */}
      <View style={s.header}>
        <TouchableOpacity style={s.backBtn} onPress={() => navigation.goBack()}>
          <Icon name="arrow-left" size={22} color="#69F0AE" />
        </TouchableOpacity>
        <Text style={s.headerTitle}>Add Product</Text>
        <View style={{ width: 44 }} />
      </View>

      <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : 'height'} style={{ flex: 1 }}>
        <ScrollView showsVerticalScrollIndicator={false} contentContainerStyle={s.scrollContent}>
          <Animated.View style={{ opacity: fadeAnim, transform: [{ translateY: slideAnim }] }}>
            {/* Image Upload */}
            <TouchableOpacity activeOpacity={0.7} style={s.imageUpload}>
              <LinearGradient colors={['rgba(255,255,255,0.06)', 'rgba(255,255,255,0.02)']} style={s.imageUploadGrad}>
                <View style={s.cameraCircle}>
                  <Icon name="camera-plus" size={28} color="#69F0AE" />
                </View>
                <Text style={s.imageUploadText}>Add Product Photo</Text>
                <Text style={s.imageUploadSub}>Tap to upload</Text>
              </LinearGradient>
            </TouchableOpacity>

            {/* Form Card */}
            <View style={s.glassCard}>
              <InputField icon="tag-outline" label="Product Name *" value={formData.name} onChangeText={t => updateFormData('name', t)} />

              {/* Category Grid */}
              <Text style={s.label}>Category</Text>
              <View style={s.catGrid}>
                {categories.map((cat) => (
                  <TouchableOpacity key={cat.value} activeOpacity={0.7} onPress={() => updateFormData('category', cat.value)}
                    style={[s.catChip, formData.category === cat.value && s.catChipActive]}>
                    {formData.category === cat.value ? (
                      <LinearGradient colors={cat.gradient} style={s.catChipGrad}>
                        <Text style={s.catIcon}>{cat.icon}</Text>
                        <Text style={s.catTextActive}>{cat.value}</Text>
                      </LinearGradient>
                    ) : (
                      <View style={s.catChipInner}>
                        <Text style={s.catIcon}>{cat.icon}</Text>
                        <Text style={s.catText}>{cat.value}</Text>
                      </View>
                    )}
                  </TouchableOpacity>
                ))}
              </View>

              {/* Price Row */}
              <View style={s.row}>
                <View style={[s.inputWrapper, { flex: 1, marginRight: 10 }]}>
                  <Text style={s.currencySymbol}>₹</Text>
                  <TextInput label="Price *" value={formData.price} onChangeText={t => updateFormData('price', t)} style={s.input} keyboardType="numeric" textColor="#fff" underlineColor="transparent" activeUnderlineColor="#00C853" theme={{ colors: { onSurfaceVariant: 'rgba(255,255,255,0.4)' } }} />
                </View>
                <View style={[s.inputWrapper, { width: 100 }]}>
                  <TextInput label="Unit" value={formData.unit} onChangeText={t => updateFormData('unit', t)} style={s.input} textColor="#fff" underlineColor="transparent" activeUnderlineColor="#00C853" theme={{ colors: { onSurfaceVariant: 'rgba(255,255,255,0.4)' } }} />
                </View>
              </View>

              <InputField icon="package-variant" label="Available Stock *" value={formData.stock} onChangeText={t => updateFormData('stock', t)} keyboardType="numeric" />
              <InputField icon="text-box-outline" label="Description" value={formData.description} onChangeText={t => updateFormData('description', t)} multiline numberOfLines={3} />

              {/* Organic Toggle */}
              <TouchableOpacity activeOpacity={0.7} onPress={() => setIsOrganic(!isOrganic)} style={[s.organicRow, isOrganic && s.organicRowActive]}>
                <View style={s.organicLeft}>
                  <Icon name="leaf" size={20} color={isOrganic ? '#00C853' : 'rgba(255,255,255,0.4)'} />
                  <Text style={[s.organicText, isOrganic && s.organicTextActive]}>Organic Product</Text>
                </View>
                <View style={[s.toggle, isOrganic && s.toggleActive]}>
                  <View style={[s.toggleDot, isOrganic && s.toggleDotActive]} />
                </View>
              </TouchableOpacity>

              {/* Submit */}
              <TouchableOpacity onPress={handleSubmit} disabled={loading} activeOpacity={0.8}>
                <LinearGradient colors={['#00C853', '#00E676']} start={{ x: 0, y: 0 }} end={{ x: 1, y: 0 }} style={s.submitBtn}>
                  <Icon name="check-circle" size={22} color="#0a1a0f" style={{ marginRight: 8 }} />
                  <Text style={s.submitText}>{loading ? 'Publishing...' : 'Publish Product'}</Text>
                </LinearGradient>
              </TouchableOpacity>
            </View>
          </Animated.View>
        </ScrollView>
      </KeyboardAvoidingView>
    </LinearGradient>
  );
}

